			cudaEvent_t start, stop;
			cudaEventCreate(&start); cudaEventCreate(&stop);
			cudaEventRecord(start);
			// Launching with half2. We need to cast d_c to half2*.
			// But d_c is double*. Size is datasize bytes.
			// half2 is 4 bytes. double is 8 bytes.
			// We can cast.
			benchmark_func_cuda<half2>(__half2half2(1.0f), (half2*)d_c, dimBlock, elements_per_wi, fusion_degree, current_compute_iterations, args.block_strided);
			cudaEventRecord(stop);
			cudaEventSynchronize(stop);
			float elapsed;
			cudaEventElapsedTime(&elapsed, start);
			kernel_time_mad_hp = elapsed;
			cudaEventDestroy(start); cudaEventDestroy(stop);
		}

		// Benchmark Int
		{
			cudaEvent_t start, stop;
			cudaEventCreate(&start); cudaEventCreate(&stop);
			cudaEventRecord(start);
			benchmark_func_cuda<int>(1, (int*)d_c, dimBlock, elements_per_wi, fusion_degree, current_compute_iterations, args.block_strided);
			cudaEventRecord(stop);
			cudaEventSynchronize(stop);
			float elapsed;
			cudaEventElapsedTime(&elapsed, start);
			kernel_time_mad_int = elapsed;
			cudaEventDestroy(start); cudaEventDestroy(stop);
		}

		printf("         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
	      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
	      current_compute_iterations,
	      ((double)computations) / ((double)memoryoperations * sizeof(float)),
	      kernel_time_mad_sp,
	      ((double)computations) / kernel_time_mad_sp * 1000. /
	          (double)(1000 * 1000 * 1000),
	      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
	          (1000. * 1000. * 1000.),
	      ((double)computations) / ((double)memoryoperations * sizeof(double)),
	      kernel_time_mad_dp,
	      ((double)computations) / kernel_time_mad_dp * 1000. /
	          (double)(1000 * 1000 * 1000),
	      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
	          (1000. * 1000. * 1000.),
	      ((double)2 * computations) /
	          ((double)memoryoperations * sizeof(short)*2), // half2 size
	      kernel_time_mad_hp,
	      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
	          (double)(1000 * 1000 * 1000),
	      ((double)memoryoperations * sizeof(short)*2) / kernel_time_mad_hp *
	          1000. / (1000. * 1000. * 1000.),
	      ((double)computations) / ((double)memoryoperations * sizeof(int)),
	      kernel_time_mad_int,
	      ((double)computations) / kernel_time_mad_int * 1000. /
	          (double)(1000 * 1000 * 1000),
	      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
	          (1000. * 1000. * 1000.));

		show_progress_step(1, '>');
	}
	show_progress_done();

	// Read back
	CUDA_SAFE_CALL(cudaMemcpy(c, d_c, datasize, cudaMemcpyDeviceToHost));
	CUDA_SAFE_CALL(cudaFree(d_c));

	printf("------------------------------------------------------------------------"
	      "------------------------------------------------------------------------"
	      "--------------------\n");

	return 0;
}
